import { contacts, groups, subGroups } from '../data/mockData';

const USE_MOCKS = process.env.REACT_APP_USE_MOCKS !== 'false';
const BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://localhost:8080/api';

async function request(path, options = {}) {
  if (USE_MOCKS) return null;
  const res = await fetch(`${BASE_URL}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options,
  });
  if (!res.ok) throw new Error(`API error ${res.status}`);
  return res.json();
}

export const api = {
  getChats: () => USE_MOCKS ? Promise.resolve([...groups, ...contacts]) : request('/chats'),
  getMessages: (chatId) => USE_MOCKS ? Promise.resolve(groups.find(g => g.id === chatId)?.messages || []) : request(`/chats/${chatId}/messages`),
  sendMessage: (chatId, text) => USE_MOCKS ? Promise.resolve({ id: Date.now(), text }) : request(`/chats/${chatId}/messages`, { method: 'POST', body: JSON.stringify({ text }) }),
  getGroups: () => USE_MOCKS ? Promise.resolve(groups) : request('/groups'),
  getSubGroups: (groupId) => USE_MOCKS ? Promise.resolve(subGroups.filter(sg => sg.parentGroupId === groupId)) : request(`/groups/${groupId}/subgroups`),
  createGroup: (data) => USE_MOCKS ? Promise.resolve({ id: `g_${Date.now()}`, ...data }) : request('/groups', { method: 'POST', body: JSON.stringify(data) }),
  createSubGroup: (groupId, data) => USE_MOCKS ? Promise.resolve({ id: `sg_${Date.now()}`, parentGroupId: groupId, ...data }) : request(`/groups/${groupId}/subgroups`, { method: 'POST', body: JSON.stringify(data) }),
  getContacts: () => USE_MOCKS ? Promise.resolve(contacts) : request('/contacts'),

  // Always calls the real backend — AI chat is never mocked
  sendAiMessage: async (message) => {
    const res = await fetch(`${BASE_URL}/ai/chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message }),
    });
    if (!res.ok) throw new Error('AI error ' + res.status);
    const data = await res.json();
    return data.reply;
  },
};
